UPDATE TBL_INV_ADJUSTMENT SET
    ADJUSTMENT_REASON = #{adjustmentReason},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{updtUser}
WHERE TBL_INV_ADJUSTMENT_ID = #{tblInvAdjustmentId}

UPDATE TBL_INV_ADJUSTMENT SET
    DELETED_YN = 'Y',
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{updtUser}
WHERE TBL_INV_ADJUSTMENT_ID = #{tblInvAdjustmentId}

